import React from 'react';
import { Link } from 'react-router-dom';

const diningCategories = [
  {
    title: 'Breakfast Favorites',
    description: 'Fresh morning plates prepared for light starts and hearty hotel breakfasts.',
    items: [
      { name: 'Classic English Breakfast', price: 'KSh 1,250' },
      { name: 'Pancake Stack With Syrup', price: 'KSh 950' },
      { name: 'Omelette & Toast Combo', price: 'KSh 780' },
      { name: 'Tropical Fruit Bowl', price: 'KSh 640' },
    ],
  },
  {
    title: 'Main Courses',
    description: 'Chef-crafted dishes with rich flavors for lunch and dinner service.',
    items: [
      { name: 'Grilled Beef Steak', price: 'KSh 2,450' },
      { name: 'Herb Chicken Supreme', price: 'KSh 1,980' },
      { name: 'Creamy Seafood Pasta', price: 'KSh 2,200' },
      { name: 'Vegetable Stir Fry Rice Bowl', price: 'KSh 1,350' },
    ],
  },
  {
    title: 'Snacks & Fast Bites',
    description: 'Quick favorites for casual dining, room service, and light meals.',
    items: [
      { name: 'Double Cheese Burger', price: 'KSh 1,150' },
      { name: 'Crispy Chicken Wrap', price: 'KSh 980' },
      { name: 'Loaded Fries Basket', price: 'KSh 720' },
      { name: 'Club Sandwich Deluxe', price: 'KSh 890' },
    ],
  },
  {
    title: 'Desserts & Drinks',
    description: 'Sweet finishes and refreshing beverages to complete your dining experience.',
    items: [
      { name: 'Chocolate Lava Cake', price: 'KSh 780' },
      { name: 'Vanilla Berry Cheesecake', price: 'KSh 860' },
      { name: 'Fresh Passion Juice', price: 'KSh 420' },
      { name: 'Signature Cappuccino', price: 'KSh 390' },
    ],
  },
];

const Dining = () => {
  return (
    <section className="dining-page">
      <div className="dining-page__hero">
        <p className="dining-page__eyebrow">Dining Experience</p>
        <h2>Explore delicious dishes across our most loved food categories.</h2>
        <p className="dining-page__intro">
          Enjoy breakfast classics, premium main dishes, quick bites, desserts, and refreshing
          drinks prepared with care by our kitchen team.
        </p>
      </div>

      <div className="dining-categories">
        {diningCategories.map((category) => (
          <article className="dining-category-card" key={category.title}>
            <div className="dining-category-card__header">
              <h3>{category.title}</h3>
              <p>{category.description}</p>
            </div>

            <div className="dining-menu-list">
              {category.items.map((item) => (
                <div className="dining-menu-item" key={item.name}>
                  <div>
                    <h4>{item.name}</h4>
                    <span>{category.title}</span>
                  </div>

                  <div className="dining-menu-item__actions">
                    <strong>{item.price}</strong>
                    <Link className="dining-order-button" to="/makepayment">
                      Order Now
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default Dining;
